{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOsIw/AZLIb43UhVxMGw3If"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"pN2W7DCYDZlK"},"outputs":[],"source":["# app.py\n","from fastapi import FastAPI, HTTPException\n","from pydantic import BaseModel\n","import joblib\n","import pandas as pd\n","\n","app = FastAPI(title=\"Sales Forecasting API\")\n","\n","# Charger le modèle UNE SEULE FOIS au démarrage (gain de performance)\n","model_package = joblib.load('model_production.pkl')\n","model = model_package['model']\n","\n","# Définition des données attendues\n","class InputData(BaseModel):\n","    onpromotion: float\n","    transactions: float\n","    is_holiday: int\n","    lag_1: float\n","    lag_7: float\n","    # ... toutes les features requises ...\n","\n","@app.post(\"/predict\")\n","def predict_sales(data: InputData):\n","    try:\n","        # Conversion en DataFrame pour sklearn\n","        df_input = pd.DataFrame([data.dict()])\n","\n","        # Vérification de l'ordre des colonnes\n","        df_input = df_input[model_package['feature_names']]\n","\n","        # Prédiction\n","        pred = model.predict(df_input)[0]\n","\n","        return {\n","            \"predicted_sales\": float(pred),\n","            \"currency\": \"USD\",\n","            \"model_version\": model_package['version']\n","        }\n","    except Exception as e:\n","        raise HTTPException(status_code=500, detail=str(e))\n","\n","# Lancer avec : uvicorn app:app --reload"]}]}